import os
from cffi import FFI
from mad import MadType, Mad

_ffi = FFI()
_ffi.cdef("""
    int CreateNamespace(char* name, char* key);
    int CreateServiceCaller(int namespace, char* serviceName, char* inputCode, char* outputCode);
    int CallService(int callerId, char* input, int input_len, char* output, int max_output, int time_out);
    int CreatePublisher(int namespace, char* publisherName, char* keyCode);
    void Publish(int publisher, char* data, int data_len);
    int CreateSubscriber(int namespace, char* topicName, char* keyCode);
    int GetSubscriberData(int subscriber, char* output, int max_output_len);
""")

_lib_path = os.path.join(os.path.dirname(__file__), "spineBridge.so")
_lib = _ffi.dlopen(_lib_path)


class SpineError(Exception):
    """Base exception for Spine-related errors."""
    pass


class Namespace:
    def __init__(self, name: str, key: str):
        self.name = name
        self.key = key

        namespace_name_c = _ffi.new("char[]", name.encode('utf-8'))
        namespace_password_c = _ffi.new("char[]", key.encode('utf-8'))

        self._id = _lib.CreateNamespace(namespace_name_c, namespace_password_c)
        if self._id < 0:
            raise SpineError(f"Failed to create namespace '{name}' (error code: {self._id})")


class ServiceCaller:
    def __init__(self, ns: Namespace, service_name: str, input_type: MadType, output_type: MadType):
        self.service_name = service_name
        self._input_serializer = Mad(input_type)
        self._output_serializer = Mad(output_type)
        self.namespace = ns

        service_name_c = _ffi.new("char[]", service_name.encode('utf-8'))
        input_code_c = _ffi.new("char[]", self._input_serializer.code.encode('utf-8'))
        output_code_c = _ffi.new("char[]", self._output_serializer.code.encode('utf-8'))

        self._id = _lib.CreateServiceCaller(ns._id, service_name_c, input_code_c, output_code_c)
        if self._id < 0:
            raise SpineError(f"Failed to create service caller '{service_name}' (error code: {self._id})")

    def call(self, data, time_out):
        serialized_input = self._input_serializer.encode(data)
        max_output = 1024
        buf = _ffi.new("char[]", max_output)

        result = _lib.CallService(self._id, serialized_input, len(serialized_input), buf, max_output, time_out)
        
        if result < 0:
            raise SpineError(f"Service call failed (error code: {result})")

        output_bytes = _ffi.buffer(buf, result)[:]
        return self._output_serializer.decode(output_bytes)


class Publisher:
    def __init__(self, ns: Namespace, name: str, output_type: MadType):
        self.name = name
        self._output_serializer = Mad(output_type)
        self.namespace = ns

        output_code_c = _ffi.new("char[]", self._output_serializer.code.encode('utf-8'))
        publisher_name_c = _ffi.new("char[]", name.encode('utf-8'))

        self._id = _lib.CreatePublisher(ns._id, publisher_name_c, output_code_c)
        if self._id < 0:
            raise SpineError(f"Failed to create publisher '{name}' (error code: {self._id})")

    def publish(self, data):
        serialized_output = self._output_serializer.encode(data)
        _lib.Publish(self._id, serialized_output, len(serialized_output))


class Subscriber:
    def __init__(self, ns: Namespace, publisher_name: str, input_type: MadType):
        self.publisher_name = publisher_name
        self._input_serializer = Mad(input_type)
        self.namespace = ns

        input_code_c = _ffi.new("char[]", self._input_serializer.code.encode('utf-8'))
        subssrbier_c = _ffi.new("char[]", publisher_name.encode('utf-8'))
        self._id = _lib.CreateSubscriber(ns._id, subssrbier_c, input_code_c)
        if self._id < 0:
            raise SpineError(f"Failed to create subscriber for '{publisher_name}' (error code: {self._id})")

    def get_data(self):
        max_output = 1024
        buf = _ffi.new("char[]", max_output)
        written_bytes = _lib.GetSubscriberData(self._id, buf, max_output)
        
        if written_bytes < 0:
            return None
            
        output_bytes = _ffi.buffer(buf, written_bytes)[:]
        return self._input_serializer.decode(output_bytes)

